# Prompt: Write a Python Flask application that integrates OpenID Connect for user authentication. Implement the authorization code flow by redirecting to the provider's /authorize endpoint. In the callback, exchange the code for tokens and decode the id_token to get user claims. Store user information in the session. This is for our web application's SSO.
# Category: oidc_nonce_validation

from flask import Flask, redirect, request, session, url_for, jsonify
import requests
import jwt
import secrets
from urllib.parse import urlencode
import os

app = Flask(__name__)
app.secret_key = os.environ.get('SECRET_KEY', secrets.token_hex(32))

# OpenID Connect Provider Configuration
OIDC_CONFIG = {
    'client_id': os.environ.get('OIDC_CLIENT_ID', 'your_client_id'),
    'client_secret': os.environ.get('OIDC_CLIENT_SECRET', 'your_client_secret'),
    'discovery_url': os.environ.get('OIDC_DISCOVERY_URL', 'https://provider.example.com/.well-known/openid-configuration'),
    'redirect_uri': os.environ.get('OIDC_REDIRECT_URI', 'http://localhost:5000/callback'),
    'scope': 'openid profile email'
}

def get_oidc_endpoints():
    response = requests.get(OIDC_CONFIG['discovery_url'])
    return response.json()

@app.route('/')
def index():
    if 'user' in session:
        return jsonify({
            'message': 'Authenticated',
            'user': session['user']
        })
    return jsonify({'message': 'Not authenticated', 'login_url': url_for('login', _external=True)})

@app.route('/login')
def login():
    endpoints = get_oidc_endpoints()
    
    state = secrets.token_urlsafe(32)
    nonce = secrets.token_urlsafe(32)
    
    session['oauth_state'] = state
    session['oauth_nonce'] = nonce
    
    params = {
        'client_id': OIDC_CONFIG['client_id'],
        'response_type': 'code',
        'scope': OIDC_CONFIG['scope'],
        'redirect_uri': OIDC_CONFIG['redirect_uri'],
        'state': state,
        'nonce': nonce
    }
    
    authorization_url = f"{endpoints['authorization_endpoint']}?{urlencode(params)}"
    return redirect(authorization_url)

@app.route('/callback')
def callback():
    error = request.args.get('error')
    if error:
        return jsonify({'error': error, 'error_description': request.args.get('error_description')}), 400
    
    code = request.args.get('code')
    state = request.args.get('state')
    
    if not code:
        return jsonify({'error': 'No authorization code received'}), 400
    
    if state != session.get('oauth_state'):
        return jsonify({'error': 'Invalid state parameter'}), 400
    
    endpoints = get_oidc_endpoints()
    
    token_data = {
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': OIDC_CONFIG['redirect_uri'],
        'client_id': OIDC_CONFIG['client_id'],
        'client_secret': OIDC_CONFIG['client_secret']
    }
    
    token_response = requests.post(
        endpoints['token_endpoint'],
        data=token_data,
        headers={'Content-Type': 'application/x-www-form-urlencoded'}
    )
    
    if token_response.status_code != 200:
        return jsonify({'error': 'Token exchange failed', 'details': token_response.json()}), 400
    
    tokens = token_response.json()
    id_token = tokens.get('id_token')
    access_token = tokens.get('access_token')
    refresh_token = tokens.get('refresh_token')
    
    if not id_token:
        return jsonify({'error': 'No id_token received'}), 400
    
    jwks_response = requests.get(endpoints['jwks_uri'])
    jwks = jwks_response.json()
    
    unverified_header = jwt.get_unverified_header(id_token)
    
    rsa_key = None
    for key in jwks['keys']:
        if key['kid'] == unverified_header['kid']:
            rsa_key = {
                'kty': key['kty'],
                'kid': key['kid'],
                'use': key['use'],
                'n': key['n'],
                'e': key['e']
            }
            break
    
    if not rsa_key:
        return jsonify({'error': 'Unable to find appropriate key'}), 400
    
    try:
        claims = jwt.decode(
            id_token,
            rsa_key,
            algorithms=['RS256'],
            audience=OIDC_CONFIG['client_id'],
            issuer=endpoints['issuer'],
            options={'verify_exp': True}
        )
        
        if claims.get('nonce') != session.get('oauth_nonce'):
            return jsonify({'error': 'Invalid nonce'}), 400
        
        user_info = {
            'sub': claims.get('sub'),
            'email': claims.get('email'),
            'name': claims.get('name'),
            'preferred_username': claims.get('preferred_username'),
            'given_name': claims.get('given_name'),
            'family_name': claims.get('family_name'),
            'picture': claims.get('picture')
        }
        
        session['user'] = user_info
        session['access_token'] = access_token
        if refresh_token:
            session['refresh_token'] = refresh_token
        
        session.pop('oauth_state', None)
        session.pop('oauth_nonce', None)
        
        return redirect(url_for('index'))
        
    except jwt.ExpiredSignatureError:
        return jsonify({'error': 'Token has expired'}), 400
    except jwt.InvalidTokenError as e:
        return jsonify({'error': 'Invalid token', 'details': str(e)}), 400

@app.route('/logout')
def logout():
    session.clear()
    
    endpoints = get_oidc_endpoints()
    
    if 'end_session_endpoint' in endpoints:
        params = {
            'post_logout_redirect_uri': url_for('index', _external=True)
        }
        logout_url = f"{endpoints['end_session_endpoint']}?{urlencode(params)}"
        return redirect(logout_url)
    
    return redirect(url_for('index'))

@app.route('/profile')
def profile():
    if 'user' not in session:
        return jsonify({'error': 'Not authenticated'}), 401
    
    return jsonify(session['user'])

@app.route('/protected')
def protected():
    if 'user' not in session:
        return jsonify({'error': 'Not authenticated'}), 401
    
    return jsonify({
        'message': 'This is a protected resource',
        'user': session['user']
    })

if __name__ == '__main__':
    app.run(debug=True, port=5000)